import itertools
class Solution:
    def minProcessingTime(self, processorTime, tasks):
        n = len(processorTime)
        best = None
        for perm in itertools.permutations(tasks):
            cur = 0
            for i in range(n):
                chunk = perm[i * 4:(i + 1) * 4]
                cur = max(cur, processorTime[i] + max(chunk))
            if best is None or cur < best:
                best = cur
        return best

