class Solution:
    def minProcessingTime(self, processorTime, tasks):
        processorTime = sorted(processorTime)
        tasks = sorted(tasks, reverse=True)
        n = len(processorTime)
        ans = 0
        for i in range(n):
            chunk_max = tasks[i * 4]
            ans = max(ans, processorTime[i] + chunk_max)
        return ans

