var minProcessingTime = function(processorTime, tasks) {
    const pt = [...processorTime].sort((a, b) => a - b);
    const t = [...tasks].sort((a, b) => b - a);
    const n = pt.length;
    let ans = 0;
    for (let i = 0; i < n; i++) {
        const chunkMax = t[i * 4];
        ans = Math.max(ans, pt[i] + chunkMax);
    }
    return ans;
};
